static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    var data = mlContext.Data.LoadFromTextFile<ChurnRawInput>(
        dataPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

    // Map "Yes"/"No" string to boolean Label column
    var keys = new[] { "Yes", "No" };
    var values = new[] { true, false };

    var pipeline = mlContext.Transforms.Conversion.MapValue(
            "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
            inputColumnName: nameof(ChurnRawInput.Churned))
        .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnRawInput.Region)))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnRawInput.Age),
            nameof(ChurnRawInput.Income),
            "RegionEncoded",
            nameof(ChurnRawInput.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
            labelColumnName: "Label", featureColumnName: "Features"));

    var model = pipeline.Fit(split.TrainSet);

    // Evaluate on test set
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

